<script lang="ts">
	import type { MouseEventHandler } from "svelte/elements";
	import Tooltip from "./Tooltip.svelte";
	import EditArea from "./EditArea.svelte";
	import { gsap } from "gsap";

	import { Draggable } from "gsap/Draggable";
	import { onMount } from "svelte";

	gsap.registerPlugin(Draggable);

	let targetArea: HTMLElement | undefined = $state();
	let renameArea: HTMLElement | undefined = $state();

	const showName: MouseEventHandler<SVGSVGElement> = (event) => {
		const target = event.target as HTMLElement;
		if (target === targetArea) {
			return;
		}
		targetArea = target;
		document
			.querySelectorAll(".target-area")
			.forEach((area) => area.classList.remove("target-area"));
		targetArea.classList.add("target-area");
	};
	const editArea: MouseEventHandler<SVGSVGElement> = (event) => {
		const target = event.target as HTMLElement;
		if (target.dataset.area) {
			renameArea = event.target as HTMLElement;
		} else {
			renameArea = undefined;
		}
	};

	onMount(() => {
		const map = document.getElementById("map");
		if (!map) {
			throw new Error("no map element or container found");
		}
		const container = map.parentNode as Element;
		Draggable.create("#map", { bounds: container, onClick: editArea });
	});
</script>

<Tooltip {targetArea} />
<EditArea {renameArea} />
